module top_module(
    clk_i,
    RSaddr_i,
    RTaddr_i,
    RDaddr_i, 
    RDdata_i,
    RegWrite_i, 
    RSdata_o, 
    RTdata_o 
);input               clk_i;
input   [4:0]       RSaddr_i;
input   [4:0]       RTaddr_i;
input   [4:0]       RDaddr_i;
input   [31:0]      RDdata_i;
input               RegWrite_i;
output  [31:0]      RSdata_o; 
output  [31:0]      RTdata_o;


reg     [31:0]      unused_register        [0:31];


assign  RSdata_o = unused_register[RSaddr_i];
assign  RTdata_o = unused_register[RTaddr_i];


always@(posedge clk_i) begin
    if(RegWrite_i)
        unused_register[RDaddr_i] <= RDdata_i;
end

endmodule
